/**
 * User notification preferences model.
 *
 * Controls how and when a user receives email notifications.
 * Designed around email as the current notification channel,
 * with per-category subscription control and frequency settings.
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently a user wants to receive email notifications.
 * - 'instant': Send immediately when triggered
 * - 'daily': Batch into a daily digest
 * - 'weekly': Batch into a weekly digest
 */
export type EmailFrequency = 'instant' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailNotificationSettings {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;

  /** Delivery frequency for non-urgent notifications. */
  frequency: EmailFrequency;

  /**
   * Notification categories the user is subscribed to.
   * If a NotificationType is not in this set, the user won't receive it.
   */
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences.
 */
export interface UserNotificationPreferences {
  userId: string;
  email: EmailNotificationSettings;
  updatedAt: Date;
}

/**
 * Input for updating a user's notification preferences.
 * All fields are optional — only provided fields are updated.
 */
export interface UpdatePreferencesInput {
  email?: {
    enabled?: boolean;
    frequency?: EmailFrequency;
    subscribedCategories?: NotificationType[];
  };
}

/**
 * Returns default notification preferences for a new user.
 * All categories enabled, instant frequency, email on.
 */
export function getDefaultPreferences(userId: string): UserNotificationPreferences {
  return {
    userId,
    email: {
      enabled: true,
      frequency: 'instant',
      subscribedCategories: [
        'order_confirmation',
        'order_status_update',
        'welcome',
        'account_update',
      ],
    },
    updatedAt: new Date(),
  };
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user notification preferences and
 * a method to check whether a specific notification should be sent
 * to a user based on their current settings.
 *
 * Storage is in-memory, consistent with other services in this codebase.
 */

import type { NotificationType } from '../models/notification.js';
import type {
  UserNotificationPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import { getDefaultPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserNotificationPreferences> = new Map();

  /**
   * Get a user's notification preferences.
   * Returns default preferences if the user has not customized them.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferences.get(userId);
    if (existing) {
      return { ...existing, email: { ...existing.email, subscribedCategories: [...existing.email.subscribedCategories] } };
    }
    const defaults = getDefaultPreferences(userId);
    this.preferences.set(userId, defaults);
    return { ...defaults, email: { ...defaults.email, subscribedCategories: [...defaults.email.subscribedCategories] } };
  }

  /**
   * Update a user's notification preferences.
   * Only provided fields are updated; others are preserved.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserNotificationPreferences {
    const current = this.getPreferences(userId);

    if (input.email) {
      if (input.email.enabled !== undefined) {
        current.email.enabled = input.email.enabled;
      }
      if (input.email.frequency !== undefined) {
        current.email.frequency = input.email.frequency;
      }
      if (input.email.subscribedCategories !== undefined) {
        current.email.subscribedCategories = [...input.email.subscribedCategories];
      }
    }

    current.updatedAt = new Date();
    this.preferences.set(userId, current);
    this.logger.info(`Updated preferences for user ${userId}`);

    return { ...current, email: { ...current.email, subscribedCategories: [...current.email.subscribedCategories] } };
  }

  /**
   * Check whether a notification of the given type should be sent to a user
   * via the email channel based on their preferences.
   *
   * Returns true if:
   * - Email notifications are enabled AND
   * - The notification type is in the user's subscribed categories
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.email.enabled) {
      this.logger.info(`Email disabled for user ${userId}, suppressing ${notificationType}`);
      return false;
    }

    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      this.logger.info(`User ${userId} not subscribed to ${notificationType}, suppressing`);
      return false;
    }

    return true;
  }

  /**
   * Remove a user's custom preferences (revert to defaults on next access).
   */
  resetPreferences(userId: string): void {
    this.preferences.delete(userId);
    this.logger.info(`Reset preferences for user ${userId}`);
  }

  /**
   * Clear all stored preferences. Useful for testing.
   */
  clearAll(): void {
    this.preferences.clear();
  }
}

